('LC_IMPORT','ADVISE','DEADLINE','MANDATORY','Vencimiento de Carta de Crédito #{operationReference}','LC #{operationReference} por #{formattedAmount} #{currency} vence el #{expiryDate}. Verificar documentos y condiciones.','URGENT','ROLE_OPERATOR',-7,'EXPIRY_DATE','["vencimiento","critico","seguimiento"]','es',1),
