('LC_IMPORT','ADVISE','COMPLIANCE_CHECK','MANDATORY','Verificación KYC/AML — #{applicantName} / #{beneficiaryName}','Verificación compliance para partes de LC #{operationReference}. Validar contra listas de sanciones.','HIGH','ROLE_MANAGER',1,'EVENT_EXECUTION','["compliance","kyc","regulatorio"]','es',3),
('LC_IMPORT','ADVISE','CLIENT_CONTACT','MANDATORY','Notificación de emisión a #{applicantName}','Notificar a #{applicantName} que LC #{operationReference} fue avisada a #{beneficiaryName} vía #{advisingBankName}.','NORMAL','ROLE_OPERATOR',0,'EVENT_EXECUTION','["cliente","notificacion","emision"]','es',4),
('LC_IMPORT','ADVISE','FOLLOW_UP','RECOMMENDED','Seguimiento de embarque — #{operationReference}','Monitorear fecha límite de embarque para LC #{operationReference}. Coordinar con #{beneficiaryName}.','NORMAL','ROLE_OPERATOR',-30,'EXPIRY_DATE','["embarque","seguimiento","logistica"]','es',5),
('LC_IMPORT','ADVISE','TASK','RECOMMENDED','Provisión de fondos #{formattedAmount} — #{applicantName}','Verificar provisión de fondos para cubrir #{formattedAmount} #{currency} de LC #{operationReference}.','HIGH','ROLE_MANAGER',3,'EVENT_EXECUTION','["fondos","tesoreria","cobertura"]','es',6),
('LC_IMPORT','ADVISE','FOLLOW_UP','RECOMMENDED','Confirmación aviso #{advisingBankName}','Verificar que #{advisingBankName} confirmó recepción del aviso de LC #{operationReference}.','NORMAL','ROLE_OPERATOR',5,'EVENT_EXECUTION','["swift","bancos","aviso"]','es',7),
('LC_IMPORT','ADVISE','COMPLIANCE_CHECK','RECOMMENDED','Revisión exposición crediticia — #{applicantName}','Evaluar exposición crediticia total de #{applicantName} con LC #{operationReference}.','NORMAL','ROLE_MANAGER',7,'EVENT_EXECUTION','["riesgo","credito","exposicion"]','es',8),
('LC_IMPORT','ADVISE','REMINDER','RECOMMENDED','Verificar cobro comisiones — #{operationReference}','Confirmar cobro de comisiones de apertura de LC #{operationReference} a #{applicantName}.','NORMAL','ROLE_OPERATOR',2,'EVENT_EXECUTION','["comisiones","cobros","ingreso"]','es',9),
('LC_IMPORT','ADVISE','TASK','OPTIONAL','Completar expediente digital — #{operationReference}','Verificar digitalización completa de documentación de LC #{operationReference}.','LOW','ROLE_OPERATOR',5,'EVENT_EXECUTION','["documentacion","archivo","expediente"]','es',10),
('LC_IMPORT','ADVISE','FOLLOW_UP','OPTIONAL','Monitoreo riesgo país — #{beneficiaryName}','Revisar indicadores de riesgo país para jurisdicción de #{beneficiaryName}.','LOW','ROLE_MANAGER',10,'EVENT_EXECUTION','["riesgo","pais","monitoreo"]','es',11),
('LC_IMPORT','ADVISE','REMINDER','OPTIONAL','Revisión periódica de vigencia — #{operationReference}','Revisión periódica del estado de LC #{operationReference}.','LOW','ROLE_OPERATOR',-60,'EXPIRY_DATE','["revision","vigencia","periodico"]','es',12),
